proof_block:
// The ensures of det_get_internal has the shape `(P_r1 && P_r2) ==> det_equal`.
// In the previous attempt every conjunct of the antecedent was asserted at the
// top level, which is *not* a free hypothesis — that's why Verus rejected
// `assert(r1.0@ == self_@[*k])` and `assert(self_.lows.greatest_lower_bound_spec(iter, glb1))`.
// We fix this by performing the entire derivation inside an `if (antecedent) { ... }`
// branch. Inside that branch the ensures-antecedent IS in scope as a hypothesis,
// and Verus's standard if-branching mechanism reduces the obligation
// `(antecedent) ==> det_equal` to "in the antecedent-branch, det_equal holds".

let iter = KeyIterator::<K>::new_spec(*k);
let glb1 = (r1.1)@;
let glb2 = (r2.1)@;

if r1.0@ == self_@[*k]
    && self_.lows.greatest_lower_bound_spec(iter, glb1)
    && r1.0@.valid_physical_address()
    && r2.0@ == self_@[*k]
    && self_.lows.greatest_lower_bound_spec(iter, glb2)
    && r2.0@.valid_physical_address()
{
    // ============================================================
    //   Antecedent of the ensures-implication is now in context.
    // ============================================================

    // IDs share the same AbstractEndPoint view (both equal self_@[*k]).
    assert(r1.0@ == self_@[*k]);
    assert(r2.0@ == self_@[*k]);
    assert(r1.0@ == r2.0@);

    // iter has a Some payload, so iter is not the end iterator.
    assert(iter.k is Some);
    assert(!iter.is_end_spec());
    assert(*iter.get_spec() == *k);

    // From the !is_end branch of greatest_lower_bound_spec, both glb_i.k must
    // be Some and refer to keys of self_.lows@.
    assert(self_.lows.greatest_lower_bound_spec(iter, glb1));
    assert(self_.lows.greatest_lower_bound_spec(iter, glb2));
    assert(glb1.k is Some);
    assert(glb2.k is Some);
    assert(self_.lows@.contains_key(glb1.k->Some_0));
    assert(self_.lows@.contains_key(glb2.k->Some_0));

    let g1 = glb1.k->Some_0;
    let g2 = glb2.k->Some_0;

    assert(KeyIterator::<K>::new_spec(g1) == glb1);
    assert(KeyIterator::<K>::new_spec(g2) == glb2);

    K::cmp_properties();

    // ------------------------------------------------------------
    //   Show glb1 == glb2 by case analysis on whether each glb_i
    //   equals iter or lies strictly below iter (the two cases
    //   allowed by GLB's first conjunct: glb == iter || glb < iter).
    // ------------------------------------------------------------
    assert(glb1 == glb2) by {
        K::cmp_properties();
        if glb1 != glb2 {
            if glb1 == iter {
                // glb1 == iter implies *k is in self_.lows@.
                assert(self_.lows@.contains_key(*k));
                // glb2 != iter, so glb2.lt_spec(iter).
                assert(glb2.lt_spec(iter));
                // pick hi2 witnessing the exists clause of GLB for glb2.
                let hi2: KeyIterator<K> = choose|hi: KeyIterator<K>|
                    #[trigger] self_.lows.gap(glb2, hi)
                    && #[trigger] KeyIterator::<K>::between(glb2, iter, hi);
                assert(self_.lows.gap(glb2, hi2));
                assert(KeyIterator::<K>::between(glb2, iter, hi2));
                assert(glb2.lt_spec(iter));
                assert(iter.lt_spec(hi2));
                // gap's forall (over ki) instantiated at ki = iter contradicts
                // self_.lows@.contains_key(*k).
                assert(forall|ki: KeyIterator<K>|
                    glb2.lt_spec(ki) && ki.lt_spec(hi2)
                    ==> !(#[trigger] self_.lows@.contains_key(*ki.get())));
                assert(!self_.lows@.contains_key(*iter.get_spec()));
                assert(*iter.get_spec() == *k);
                assert(!self_.lows@.contains_key(*k));
            } else if glb2 == iter {
                assert(self_.lows@.contains_key(*k));
                assert(glb1.lt_spec(iter));
                let hi1: KeyIterator<K> = choose|hi: KeyIterator<K>|
                    #[trigger] self_.lows.gap(glb1, hi)
                    && #[trigger] KeyIterator::<K>::between(glb1, iter, hi);
                assert(self_.lows.gap(glb1, hi1));
                assert(KeyIterator::<K>::between(glb1, iter, hi1));
                assert(glb1.lt_spec(iter));
                assert(iter.lt_spec(hi1));
                assert(forall|ki: KeyIterator<K>|
                    glb1.lt_spec(ki) && ki.lt_spec(hi1)
                    ==> !(#[trigger] self_.lows@.contains_key(*ki.get())));
                assert(!self_.lows@.contains_key(*iter.get_spec()));
                assert(*iter.get_spec() == *k);
                assert(!self_.lows@.contains_key(*k));
            } else {
                // Both glb_i lie strictly below iter, so g_i.cmp(*k).lt().
                assert(glb1.lt_spec(iter));
                assert(glb2.lt_spec(iter));
                assert(g1.cmp_spec(*k).lt());
                assert(g2.cmp_spec(*k).lt());
                // iter.above_spec(g_i) holds because iter.k = Some(*k) and g_i < *k.
                assert(iter.above_spec(g1));
                assert(iter.above_spec(g2));
                // KeyIterator::new_spec(g_j) != glb_i for the cross pair because
                // glb1 != glb2 and KeyIterator::new_spec(g_j) == glb_j.
                assert(KeyIterator::<K>::new_spec(g2) != glb1);
                assert(KeyIterator::<K>::new_spec(g1) != glb2);
                // The maximality forall in greatest_lower_bound_spec, trigger
                // self@.contains_key(g_j), now fires both ways.
                assert(glb1.above_spec(g2));
                assert(glb2.above_spec(g1));
                // Unfolding above_spec on Some payloads: g2 < g1 and g1 < g2.
                // Contradiction with asymmetry from K::cmp_properties.
                assert(g2.cmp_spec(g1).lt());
                assert(g1.cmp_spec(g2).lt());
            }
        }
    };

    // Lift glb equality to (r1.1)@ == (r2.1)@.
    assert((r1.1)@ == glb1);
    assert((r2.1)@ == glb2);
    assert((r1.1)@ == (r2.1)@);
    assert((r1.1)@.k == (r2.1)@.k);

    // Spell out the two .k conjuncts of det_get_internal_equal explicitly,
    // so they aren't left for SMT to derive after-the-fact.
    assert(((r1.1)@.k is Some) == ((r2.1)@.k is Some));
    assert(((r1.1)@.k is Some) ==> ((r1.1)@.k->Some_0 == (r2.1)@.k->Some_0));

    // r1.0 and r2.0 share the same AbstractEndPoint view, and EndPoint is a
    // struct with a single Vec<u8> field whose @ projection determines it.
    assert(r1.0.id@ == r2.0.id@);
    assert(r1.0.id =~= r2.0.id);
    assert(r1.0 == r2.0);

    // All three conjuncts of det_get_internal_equal are now established.
    assert(det_get_internal_equal(r1, r2));
}
